module RefModule(
    input  wire        clk,
    input  wire        clr,
    input  wire [ 7:0] A,
    input  wire [ 7:0] B,
    output reg  [15:0] Z
);reg [15:0] obf_acc;

    always @(posedge clk) begin
        if (clr) begin
            obf_acc <= 0;
        end else begin
            obf_acc <= A * B;
        end
    end

    assign Z = obf_acc;

endmodule
